     1→import * as fs from 'node:fs';
     2→import { parse as parseYaml } from 'yaml';
     3→import { SchemaYamlSchema, type SchemaYaml, type Artifact } from './types.js';
     4→
     5→export class SchemaValidationError extends Error {
     6→  constructor(message: string) {
     7→    super(message);
     8→    this.name = 'SchemaValidationError';
     9→  }
    10→}
    11→
    12→/**
    13→ * Loads and validates an artifact schema from a YAML file.
    14→ */
    15→export function loadSchema(filePath: string): SchemaYaml {
    16→  const content = fs.readFileSync(filePath, 'utf-8');
    17→  return parseSchema(content);
    18→}
    19→
    20→/**
    21→ * Parses and validates an artifact schema from YAML content.
    22→ */
    23→export function parseSchema(yamlContent: string): SchemaYaml {
    24→  const parsed = parseYaml(yamlContent);
    25→
    26→  // Validate with Zod
    27→  const result = SchemaYamlSchema.safeParse(parsed);
    28→  if (!result.success) {
    29→    const errors = result.error.issues.map(e => `${e.path.join('.')}: ${e.message}`).join(', ');
    30→    throw new SchemaValidationError(`Invalid schema: ${errors}`);
    31→  }
    32→
    33→  const schema = result.data;
    34→
    35→  // Check for duplicate artifact IDs
    36→  validateNoDuplicateIds(schema.artifacts);
    37→
    38→  // Check that all requires references are valid
    39→  validateRequiresReferences(schema.artifacts);
    40→
    41→  // Check for cycles
    42→  validateNoCycles(schema.artifacts);
    43→
    44→  return schema;
    45→}
    46→
    47→/**
    48→ * Validates that there are no duplicate artifact IDs.
    49→ */
    50→function validateNoDuplicateIds(artifacts: Artifact[]): void {
    51→  const seen = new Set<string>();
    52→  for (const artifact of artifacts) {
    53→    if (seen.has(artifact.id)) {
    54→      throw new SchemaValidationError(`Duplicate artifact ID: ${artifact.id}`);
    55→    }
    56→    seen.add(artifact.id);
    57→  }
    58→}
    59→
    60→/**
    61→ * Validates that all `requires` references point to valid artifact IDs.
    62→ */
    63→function validateRequiresReferences(artifacts: Artifact[]): void {
    64→  const validIds = new Set(artifacts.map(a => a.id));
    65→
    66→  for (const artifact of artifacts) {
    67→    for (const req of artifact.requires) {
    68→      if (!validIds.has(req)) {
    69→        throw new SchemaValidationError(
    70→          `Invalid dependency reference in artifact '${artifact.id}': '${req}' does not exist`
    71→        );
    72→      }
    73→    }
    74→  }
    75→}
    76→
    77→/**
    78→ * Validates that there are no cyclic dependencies.
    79→ * Uses DFS to detect cycles and reports the full cycle path.
    80→ */
    81→function validateNoCycles(artifacts: Artifact[]): void {
    82→  const artifactMap = new Map(artifacts.map(a => [a.id, a]));
    83→  const visited = new Set<string>();
    84→  const inStack = new Set<string>();
    85→  const parent = new Map<string, string>();
    86→
    87→  function dfs(id: string): string | null {
    88→    visited.add(id);
    89→    inStack.add(id);
    90→
    91→    const artifact = artifactMap.get(id);
    92→    if (!artifact) return null;
    93→
    94→    for (const dep of artifact.requires) {
    95→      if (!visited.has(dep)) {
    96→        parent.set(dep, id);
    97→        const cycle = dfs(dep);
    98→        if (cycle) return cycle;
    99→      } else if (inStack.has(dep)) {
   100→        // Found a cycle - reconstruct the path
   101→        const cyclePath = [dep];
   102→        let current = id;
   103→        while (current !== dep) {
   104→          cyclePath.unshift(current);
   105→          current = parent.get(current)!;
   106→        }
   107→        cyclePath.unshift(dep);
   108→        return cyclePath.join(' → ');
   109→      }
   110→    }
   111→
   112→    inStack.delete(id);
   113→    return null;
   114→  }
   115→
   116→  for (const artifact of artifacts) {
   117→    if (!visited.has(artifact.id)) {
   118→      const cycle = dfs(artifact.id);
   119→      if (cycle) {
   120→        throw new SchemaValidationError(`Cyclic dependency detected: ${cycle}`);
   121→      }
   122→    }
   123→  }
   124→}
