     1→import type { Artifact, SchemaYaml, CompletedSet, BlockedArtifacts } from './types.js';
     2→import { loadSchema, parseSchema } from './schema.js';
     3→
     4→/**
     5→ * Represents an artifact dependency graph.
     6→ * Provides methods for querying build order, ready artifacts, and completion status.
     7→ */
     8→export class ArtifactGraph {
     9→  private artifacts: Map<string, Artifact>;
    10→  private schema: SchemaYaml;
    11→
    12→  private constructor(schema: SchemaYaml) {
    13→    this.schema = schema;
    14→    this.artifacts = new Map(schema.artifacts.map(a => [a.id, a]));
    15→  }
    16→
    17→  /**
    18→   * Creates an ArtifactGraph from a YAML file path.
    19→   */
    20→  static fromYaml(filePath: string): ArtifactGraph {
    21→    const schema = loadSchema(filePath);
    22→    return new ArtifactGraph(schema);
    23→  }
    24→
    25→  /**
    26→   * Creates an ArtifactGraph from YAML content string.
    27→   */
    28→  static fromYamlContent(yamlContent: string): ArtifactGraph {
    29→    const schema = parseSchema(yamlContent);
    30→    return new ArtifactGraph(schema);
    31→  }
    32→
    33→  /**
    34→   * Creates an ArtifactGraph from a pre-validated schema object.
    35→   */
    36→  static fromSchema(schema: SchemaYaml): ArtifactGraph {
    37→    return new ArtifactGraph(schema);
    38→  }
    39→
    40→  /**
    41→   * Gets a single artifact by ID.
    42→   */
    43→  getArtifact(id: string): Artifact | undefined {
    44→    return this.artifacts.get(id);
    45→  }
    46→
    47→  /**
    48→   * Gets all artifacts in the graph.
    49→   */
    50→  getAllArtifacts(): Artifact[] {
    51→    return Array.from(this.artifacts.values());
    52→  }
    53→
    54→  /**
    55→   * Gets the schema name.
    56→   */
    57→  getName(): string {
    58→    return this.schema.name;
    59→  }
    60→
    61→  /**
    62→   * Gets the schema version.
    63→   */
    64→  getVersion(): number {
    65→    return this.schema.version;
    66→  }
    67→
    68→  /**
    69→   * Computes the topological build order using Kahn's algorithm.
    70→   * Returns artifact IDs in the order they should be built.
    71→   */
    72→  getBuildOrder(): string[] {
    73→    const inDegree = new Map<string, number>();
    74→    const dependents = new Map<string, string[]>();
    75→
    76→    // Initialize all artifacts
    77→    for (const artifact of this.artifacts.values()) {
    78→      inDegree.set(artifact.id, artifact.requires.length);
    79→      dependents.set(artifact.id, []);
    80→    }
    81→
    82→    // Build reverse adjacency (who depends on whom)
    83→    for (const artifact of this.artifacts.values()) {
    84→      for (const req of artifact.requires) {
    85→        dependents.get(req)!.push(artifact.id);
    86→      }
    87→    }
    88→
    89→    // Start with roots (in-degree 0), sorted for determinism
    90→    const queue = [...this.artifacts.keys()]
    91→      .filter(id => inDegree.get(id) === 0)
    92→      .sort();
    93→
    94→    const result: string[] = [];
    95→
    96→    while (queue.length > 0) {
    97→      const current = queue.shift()!;
    98→      result.push(current);
    99→
   100→      // Collect newly ready artifacts, then sort before adding
   101→      const newlyReady: string[] = [];
   102→      for (const dep of dependents.get(current)!) {
   103→        const newDegree = inDegree.get(dep)! - 1;
   104→        inDegree.set(dep, newDegree);
   105→        if (newDegree === 0) {
   106→          newlyReady.push(dep);
   107→        }
   108→      }
   109→      queue.push(...newlyReady.sort());
   110→    }
   111→
   112→    return result;
   113→  }
   114→
   115→  /**
   116→   * Gets artifacts that are ready to be created (all dependencies completed).
   117→   */
   118→  getNextArtifacts(completed: CompletedSet): string[] {
   119→    const ready: string[] = [];
   120→
   121→    for (const artifact of this.artifacts.values()) {
   122→      if (completed.has(artifact.id)) {
   123→        continue; // Already completed
   124→      }
   125→
   126→      const allDepsCompleted = artifact.requires.every(req => completed.has(req));
   127→      if (allDepsCompleted) {
   128→        ready.push(artifact.id);
   129→      }
   130→    }
   131→
   132→    // Sort for deterministic ordering
   133→    return ready.sort();
   134→  }
   135→
   136→  /**
   137→   * Checks if all artifacts in the graph are completed.
   138→   */
   139→  isComplete(completed: CompletedSet): boolean {
   140→    for (const artifact of this.artifacts.values()) {
   141→      if (!completed.has(artifact.id)) {
   142→        return false;
   143→      }
   144→    }
   145→    return true;
   146→  }
   147→
   148→  /**
   149→   * Gets blocked artifacts and their unmet dependencies.
   150→   */
   151→  getBlocked(completed: CompletedSet): BlockedArtifacts {
   152→    const blocked: BlockedArtifacts = {};
   153→
   154→    for (const artifact of this.artifacts.values()) {
   155→      if (completed.has(artifact.id)) {
   156→        continue; // Already completed
   157→      }
   158→
   159→      const unmetDeps = artifact.requires.filter(req => !completed.has(req));
   160→      if (unmetDeps.length > 0) {
   161→        blocked[artifact.id] = unmetDeps.sort();
   162→      }
   163→    }
   164→
   165→    return blocked;
   166→  }
   167→}
