     1→import * as fs from 'node:fs';
     2→import * as path from 'node:path';
     3→import { fileURLToPath } from 'node:url';
     4→import { getGlobalDataDir } from '../global-config.js';
     5→import { parseSchema, SchemaValidationError } from './schema.js';
     6→import type { SchemaYaml } from './types.js';
     7→
     8→/**
     9→ * Error thrown when loading a schema fails.
    10→ */
    11→export class SchemaLoadError extends Error {
    12→  constructor(
    13→    message: string,
    14→    public readonly schemaPath: string,
    15→    public readonly cause?: Error
    16→  ) {
    17→    super(message);
    18→    this.name = 'SchemaLoadError';
    19→  }
    20→}
    21→
    22→/**
    23→ * Gets the package's built-in schemas directory path.
    24→ * Uses import.meta.url to resolve relative to the current module.
    25→ */
    26→export function getPackageSchemasDir(): string {
    27→  const currentFile = fileURLToPath(import.meta.url);
    28→  // Navigate from dist/core/artifact-graph/ to package root's schemas/
    29→  return path.join(path.dirname(currentFile), '..', '..', '..', 'schemas');
    30→}
    31→
    32→/**
    33→ * Gets the user's schema override directory path.
    34→ */
    35→export function getUserSchemasDir(): string {
    36→  return path.join(getGlobalDataDir(), 'schemas');
    37→}
    38→
    39→/**
    40→ * Gets the project-local schemas directory path.
    41→ * @param projectRoot - The project root directory
    42→ * @returns The path to the project's schemas directory
    43→ */
    44→export function getProjectSchemasDir(projectRoot: string): string {
    45→  return path.join(projectRoot, 'openspec', 'schemas');
    46→}
    47→
    48→/**
    49→ * Resolves a schema name to its directory path.
    50→ *
    51→ * Resolution order (when projectRoot is provided):
    52→ * 1. Project-local: <projectRoot>/openspec/schemas/<name>/schema.yaml
    53→ * 2. User override: ${XDG_DATA_HOME}/openspec/schemas/<name>/schema.yaml
    54→ * 3. Package built-in: <package>/schemas/<name>/schema.yaml
    55→ *
    56→ * When projectRoot is not provided, only user override and package built-in are checked
    57→ * (backward compatible behavior).
    58→ *
    59→ * @param name - Schema name (e.g., "spec-driven")
    60→ * @param projectRoot - Optional project root directory for project-local schema resolution
    61→ * @returns The path to the schema directory, or null if not found
    62→ */
    63→export function getSchemaDir(
    64→  name: string,
    65→  projectRoot?: string
    66→): string | null {
    67→  // 1. Check project-local directory (if projectRoot provided)
    68→  if (projectRoot) {
    69→    const projectDir = path.join(getProjectSchemasDir(projectRoot), name);
    70→    const projectSchemaPath = path.join(projectDir, 'schema.yaml');
    71→    if (fs.existsSync(projectSchemaPath)) {
    72→      return projectDir;
    73→    }
    74→  }
    75→
    76→  // 2. Check user override directory
    77→  const userDir = path.join(getUserSchemasDir(), name);
    78→  const userSchemaPath = path.join(userDir, 'schema.yaml');
    79→  if (fs.existsSync(userSchemaPath)) {
    80→    return userDir;
    81→  }
    82→
    83→  // 3. Check package built-in directory
    84→  const packageDir = path.join(getPackageSchemasDir(), name);
    85→  const packageSchemaPath = path.join(packageDir, 'schema.yaml');
    86→  if (fs.existsSync(packageSchemaPath)) {
    87→    return packageDir;
    88→  }
    89→
    90→  return null;
    91→}
    92→
    93→/**
    94→ * Resolves a schema name to a SchemaYaml object.
    95→ *
    96→ * Resolution order (when projectRoot is provided):
    97→ * 1. Project-local: <projectRoot>/openspec/schemas/<name>/schema.yaml
    98→ * 2. User override: ${XDG_DATA_HOME}/openspec/schemas/<name>/schema.yaml
    99→ * 3. Package built-in: <package>/schemas/<name>/schema.yaml
   100→ *
   101→ * When projectRoot is not provided, only user override and package built-in are checked
   102→ * (backward compatible behavior).
   103→ *
   104→ * @param name - Schema name (e.g., "spec-driven")
   105→ * @param projectRoot - Optional project root directory for project-local schema resolution
   106→ * @returns The resolved schema object
   107→ * @throws Error if schema is not found in any location
   108→ */
   109→export function resolveSchema(name: string, projectRoot?: string): SchemaYaml {
   110→  // Normalize name (remove .yaml extension if provided)
   111→  const normalizedName = name.replace(/\.ya?ml$/, '');
   112→
   113→  const schemaDir = getSchemaDir(normalizedName, projectRoot);
   114→  if (!schemaDir) {
   115→    const availableSchemas = listSchemas(projectRoot);
   116→    throw new Error(
   117→      `Schema '${normalizedName}' not found. Available schemas: ${availableSchemas.join(', ')}`
   118→    );
   119→  }
   120→
   121→  const schemaPath = path.join(schemaDir, 'schema.yaml');
   122→
   123→  // Load and parse the schema
   124→  let content: string;
   125→  try {
   126→    content = fs.readFileSync(schemaPath, 'utf-8');
   127→  } catch (err) {
   128→    const ioError = err instanceof Error ? err : new Error(String(err));
   129→    throw new SchemaLoadError(
   130→      `Failed to read schema at '${schemaPath}': ${ioError.message}`,
   131→      schemaPath,
   132→      ioError
   133→    );
   134→  }
   135→
   136→  try {
   137→    return parseSchema(content);
   138→  } catch (err) {
   139→    if (err instanceof SchemaValidationError) {
   140→      throw new SchemaLoadError(
   141→        `Invalid schema at '${schemaPath}': ${err.message}`,
   142→        schemaPath,
   143→        err
   144→      );
   145→    }
   146→    const parseError = err instanceof Error ? err : new Error(String(err));
   147→    throw new SchemaLoadError(
   148→      `Failed to parse schema at '${schemaPath}': ${parseError.message}`,
   149→      schemaPath,
   150→      parseError
   151→    );
   152→  }
   153→}
   154→
   155→/**
   156→ * Lists all available schema names.
   157→ * Combines project-local, user override, and package built-in schemas.
   158→ *
   159→ * @param projectRoot - Optional project root directory for project-local schema resolution
   160→ */
   161→export function listSchemas(projectRoot?: string): string[] {
   162→  const schemas = new Set<string>();
   163→
   164→  // Add package built-in schemas
   165→  const packageDir = getPackageSchemasDir();
   166→  if (fs.existsSync(packageDir)) {
   167→    for (const entry of fs.readdirSync(packageDir, { withFileTypes: true })) {
   168→      if (entry.isDirectory()) {
   169→        const schemaPath = path.join(packageDir, entry.name, 'schema.yaml');
   170→        if (fs.existsSync(schemaPath)) {
   171→          schemas.add(entry.name);
   172→        }
   173→      }
   174→    }
   175→  }
   176→
   177→  // Add user override schemas (may override package schemas)
   178→  const userDir = getUserSchemasDir();
   179→  if (fs.existsSync(userDir)) {
   180→    for (const entry of fs.readdirSync(userDir, { withFileTypes: true })) {
   181→      if (entry.isDirectory()) {
   182→        const schemaPath = path.join(userDir, entry.name, 'schema.yaml');
   183→        if (fs.existsSync(schemaPath)) {
   184→          schemas.add(entry.name);
   185→        }
   186→      }
   187→    }
   188→  }
   189→
   190→  // Add project-local schemas (if projectRoot provided)
   191→  if (projectRoot) {
   192→    const projectDir = getProjectSchemasDir(projectRoot);
   193→    if (fs.existsSync(projectDir)) {
   194→      for (const entry of fs.readdirSync(projectDir, { withFileTypes: true })) {
   195→        if (entry.isDirectory()) {
   196→          const schemaPath = path.join(projectDir, entry.name, 'schema.yaml');
   197→          if (fs.existsSync(schemaPath)) {
   198→            schemas.add(entry.name);
   199→          }
   200→        }
   201→      }
   202→    }
   203→  }
   204→
   205→  return Array.from(schemas).sort();
   206→}
   207→
   208→/**
   209→ * Schema info with metadata (name, description, artifacts).
   210→ */
   211→export interface SchemaInfo {
   212→  name: string;
   213→  description: string;
   214→  artifacts: string[];
   215→  source: 'project' | 'user' | 'package';
   216→}
   217→
   218→/**
   219→ * Lists all available schemas with their descriptions and artifact lists.
   220→ * Useful for agent skills to present schema selection to users.
   221→ *
   222→ * @param projectRoot - Optional project root directory for project-local schema resolution
   223→ */
   224→export function listSchemasWithInfo(projectRoot?: string): SchemaInfo[] {
   225→  const schemas: SchemaInfo[] = [];
   226→  const seenNames = new Set<string>();
   227→
   228→  // Add project-local schemas first (highest priority, if projectRoot provided)
   229→  if (projectRoot) {
   230→    const projectDir = getProjectSchemasDir(projectRoot);
   231→    if (fs.existsSync(projectDir)) {
   232→      for (const entry of fs.readdirSync(projectDir, { withFileTypes: true })) {
   233→        if (entry.isDirectory()) {
   234→          const schemaPath = path.join(projectDir, entry.name, 'schema.yaml');
   235→          if (fs.existsSync(schemaPath)) {
   236→            try {
   237→              const schema = parseSchema(fs.readFileSync(schemaPath, 'utf-8'));
   238→              schemas.push({
   239→                name: entry.name,
   240→                description: schema.description || '',
   241→                artifacts: schema.artifacts.map((a) => a.id),
   242→                source: 'project',
   243→              });
   244→              seenNames.add(entry.name);
   245→            } catch {
   246→              // Skip invalid schemas
   247→            }
   248→          }
   249→        }
   250→      }
   251→    }
   252→  }
   253→
   254→  // Add user override schemas (if not overridden by project)
   255→  const userDir = getUserSchemasDir();
   256→  if (fs.existsSync(userDir)) {
   257→    for (const entry of fs.readdirSync(userDir, { withFileTypes: true })) {
   258→      if (entry.isDirectory() && !seenNames.has(entry.name)) {
   259→        const schemaPath = path.join(userDir, entry.name, 'schema.yaml');
   260→        if (fs.existsSync(schemaPath)) {
   261→          try {
   262→            const schema = parseSchema(fs.readFileSync(schemaPath, 'utf-8'));
   263→            schemas.push({
   264→              name: entry.name,
   265→              description: schema.description || '',
   266→              artifacts: schema.artifacts.map((a) => a.id),
   267→              source: 'user',
   268→            });
   269→            seenNames.add(entry.name);
   270→          } catch {
   271→            // Skip invalid schemas
   272→          }
   273→        }
   274→      }
   275→    }
   276→  }
   277→
   278→  // Add package built-in schemas (if not overridden by project or user)
   279→  const packageDir = getPackageSchemasDir();
   280→  if (fs.existsSync(packageDir)) {
   281→    for (const entry of fs.readdirSync(packageDir, { withFileTypes: true })) {
   282→      if (entry.isDirectory() && !seenNames.has(entry.name)) {
   283→        const schemaPath = path.join(packageDir, entry.name, 'schema.yaml');
   284→        if (fs.existsSync(schemaPath)) {
   285→          try {
   286→            const schema = parseSchema(fs.readFileSync(schemaPath, 'utf-8'));
   287→            schemas.push({
   288→              name: entry.name,
   289→              description: schema.description || '',
   290→              artifacts: schema.artifacts.map((a) => a.id),
   291→              source: 'package',
   292→            });
   293→          } catch {
   294→            // Skip invalid schemas
   295→          }
   296→        }
   297→      }
   298→    }
   299→  }
   300→
   301→  return schemas.sort((a, b) => a.name.localeCompare(b.name));
   302→}
