     7→
     8→/**
     9→ * Detects which artifacts are completed by checking file existence in the change directory.
    10→ * Returns a Set of completed artifact IDs.
    11→ *
    12→ * @param graph - The artifact graph to check
    13→ * @param changeDir - The change directory to scan for files
    14→ * @returns Set of artifact IDs whose generated files exist
    15→ */
    16→export function detectCompleted(graph: ArtifactGraph, changeDir: string): CompletedSet {
    17→  const completed = new Set<string>();
    18→
    19→  // Handle missing change directory gracefully
    20→  if (!fs.existsSync(changeDir)) {
    21→    return completed;
    22→  }
    23→
    24→  for (const artifact of graph.getAllArtifacts()) {
    25→    if (isArtifactComplete(artifact.generates, changeDir)) {
    26→      completed.add(artifact.id);
    27→    }
    28→  }
    29→
    30→  return completed;
    31→}
    32→
    33→/**
    34→ * Checks if an artifact is complete by checking if its generated file(s) exist.
    35→ * Supports both simple paths and glob patterns.
    36→ */
    37→function isArtifactComplete(generates: string, changeDir: string): boolean {
    38→  const fullPattern = path.join(changeDir, generates);
    39→
    40→  // Check if it's a glob pattern
    41→  if (isGlobPattern(generates)) {
    42→    return hasGlobMatches(fullPattern);
    43→  }
    44→
    45→  // Simple file path - check if file exists
    46→  return fs.existsSync(fullPattern);
    47→}
    48→
    49→/**
    50→ * Checks if a path contains glob pattern characters.
    51→ */
    52→function isGlobPattern(pattern: string): boolean {
    53→  return pattern.includes('*') || pattern.includes('?') || pattern.includes('[');
    54→}
    55→
    56→/**
    57→ * Checks if a glob pattern has any matches.
    58→ * Normalizes Windows backslashes to forward slashes for cross-platform glob compatibility.
    59→ */
    60→function hasGlobMatches(pattern: string): boolean {
    61→  const normalizedPattern = FileSystemUtils.toPosixPath(pattern);
    62→  const matches = fg.sync(normalizedPattern, { onlyFiles: true });
    63→  return matches.length > 0;
    64→}
