   118→/**
   119→ * Loads a template from a schema's templates directory.
   120→ *
   121→ * @param schemaName - Schema name (e.g., "spec-driven")
   122→ * @param templatePath - Relative path within the templates directory (e.g., "proposal.md")
   123→ * @param projectRoot - Optional project root for project-local schema resolution
   124→ * @returns The template content
   125→ * @throws TemplateLoadError if the template cannot be loaded
   126→ */
   127→export function loadTemplate(
   128→  schemaName: string,
   129→  templatePath: string,
   130→  projectRoot?: string
   131→): string {
   132→  const schemaDir = getSchemaDir(schemaName, projectRoot);
   133→  if (!schemaDir) {
   134→    throw new TemplateLoadError(
   135→      `Schema '${schemaName}' not found`,
   136→      templatePath
   137→    );
   138→  }
   139→
   140→  const fullPath = path.join(schemaDir, 'templates', templatePath);
   141→
   142→  if (!fs.existsSync(fullPath)) {
   143→    throw new TemplateLoadError(
   144→      `Template not found: ${fullPath}`,
   145→      fullPath
   146→    );
   147→  }
   148→
   149→  try {
   150→    return fs.readFileSync(fullPath, 'utf-8');
   151→  } catch (err) {
   152→    const ioError = err instanceof Error ? err : new Error(String(err));
   153→    throw new TemplateLoadError(
   154→      `Failed to read template: ${ioError.message}`,
   155→      fullPath
   156→    );
   157→  }
   158→}
