   160→/**
   161→ * Loads change context combining graph and completion state.
   162→ *
   163→ * Schema resolution order:
   164→ * 1. Explicit schemaName parameter (if provided)
   165→ * 2. Schema from .openspec.yaml metadata (if exists in change directory)
   166→ * 3. Default 'spec-driven'
   167→ *
   168→ * @param projectRoot - Project root directory
   169→ * @param changeName - Change name
   170→ * @param schemaName - Optional schema name override. If not provided, auto-detected from metadata.
   171→ * @returns Change context with graph, completed set, and metadata
   172→ */
   173→export function loadChangeContext(
   174→  projectRoot: string,
   175→  changeName: string,
   176→  schemaName?: string
   177→): ChangeContext {
   178→  const changeDir = path.join(projectRoot, 'openspec', 'changes', changeName);
   179→
   180→  // Resolve schema: explicit > metadata > default
   181→  const resolvedSchemaName = resolveSchemaForChange(changeDir, schemaName);
   182→
   183→  const schema = resolveSchema(resolvedSchemaName, projectRoot);
   184→  const graph = ArtifactGraph.fromSchema(schema);
   185→  const completed = detectCompleted(graph, changeDir);
   186→
   187→  return {
   188→    graph,
   189→    completed,
   190→    schemaName: resolvedSchemaName,
   191→    changeName,
   192→    changeDir,
   193→    projectRoot,
   194→  };
   195→}
   196→
   197→/**
   198→ * Generates enriched instructions for creating an artifact.
   199→ *
   200→ * Instruction injection order:
   201→ * 1. <context> - Project context from config (if present)
   202→ * 2. <rules> - Artifact-specific rules from config (if present)
   203→ * 3. <template> - Schema's template content
   204→ *
   205→ * @param context - Change context
   206→ * @param artifactId - Artifact ID to generate instructions for
   207→ * @param projectRoot - Project root directory (for reading config)
   208→ * @returns Enriched artifact instructions
   209→ * @throws Error if artifact not found
   210→ */
   211→export function generateInstructions(
   212→  context: ChangeContext,
   213→  artifactId: string,
   214→  projectRoot?: string
   215→): ArtifactInstructions {
   216→  const artifact = context.graph.getArtifact(artifactId);
   217→  if (!artifact) {
   218→    throw new Error(`Artifact '${artifactId}' not found in schema '${context.schemaName}'`);
   219→  }
   220→
   221→  const templateContent = loadTemplate(context.schemaName, artifact.template, context.projectRoot);
   222→  const dependencies = getDependencyInfo(artifact, context.graph, context.completed);
   223→  const unlocks = getUnlockedArtifacts(context.graph, artifactId);
   224→
   225→  // Use projectRoot from context if not explicitly provided
   226→  const effectiveProjectRoot = projectRoot ?? context.projectRoot;
   227→
   228→  // Try to read project config for context and rules
   229→  let projectConfig = null;
   230→  if (effectiveProjectRoot) {
   231→    try {
   232→      projectConfig = readProjectConfig(effectiveProjectRoot);
   233→    } catch {
   234→      // If config read fails, continue without config
   235→    }
   236→  }
   237→
   238→  // Validate rules artifact IDs if config has rules (only once per session)
   239→  if (projectConfig?.rules) {
   240→    const validArtifactIds = new Set(context.graph.getAllArtifacts().map((a) => a.id));
   241→    const warnings = validateConfigRules(
   242→      projectConfig.rules,
   243→      validArtifactIds,
   244→      context.schemaName
   245→    );
   246→
   247→    // Show each unique warning only once per session
   248→    for (const warning of warnings) {
   249→      if (!shownWarnings.has(warning)) {
   250→        console.warn(warning);
   251→        shownWarnings.add(warning);
   252→      }
   253→    }
   254→  }
   255→
   256→  // Extract context and rules as separate fields (not prepended to template)
   257→  const configContext = projectConfig?.context?.trim() || undefined;
   258→  const rulesForArtifact = projectConfig?.rules?.[artifactId];
   259→  const configRules = rulesForArtifact && rulesForArtifact.length > 0 ? rulesForArtifact : undefined;
   260→
   261→  return {
   262→    changeName: context.changeName,
   263→    artifactId: artifact.id,
   264→    schemaName: context.schemaName,
   265→    changeDir: context.changeDir,
   266→    outputPath: artifact.generates,
   267→    description: artifact.description,
   268→    instruction: artifact.instruction,
   269→    context: configContext,
   270→    rules: configRules,
   271→    template: templateContent,
   272→    dependencies,
   273→    unlocks,
   274→  };
   275→}
   276→
   277→/**
   278→ * Gets dependency info including paths and descriptions.
   279→ */
   280→function getDependencyInfo(
   281→  artifact: Artifact,
   282→  graph: ArtifactGraph,
   283→  completed: CompletedSet
   284→): DependencyInfo[] {
   285→  return artifact.requires.map(id => {
   286→    const depArtifact = graph.getArtifact(id);
   287→    return {
   288→      id,
   289→      done: completed.has(id),
   290→      path: depArtifact?.generates ?? id,
   291→      description: depArtifact?.description ?? '',
   292→    };
   293→  });
   294→}
   295→
   296→/**
   297→ * Gets artifacts that become available after completing the given artifact.
   298→ */
   299→function getUnlockedArtifacts(graph: ArtifactGraph, artifactId: string): string[] {
   300→  const unlocks: string[] = [];
   301→
   302→  for (const artifact of graph.getAllArtifacts()) {
   303→    if (artifact.requires.includes(artifactId)) {
   304→      unlocks.push(artifact.id);
   305→    }
   306→  }
   307→
   308→  return unlocks.sort();
   309→}
   310→
   311→/**
   312→ * Formats the status of all artifacts in a change.
   313→ *
   314→ * @param context - Change context
   315→ * @returns Formatted change status
   316→ */
   317→export function formatChangeStatus(context: ChangeContext): ChangeStatus {
   318→  // Load schema to get apply phase configuration
   319→  const schema = resolveSchema(context.schemaName, context.projectRoot);
   320→  const applyRequires = schema.apply?.requires ?? schema.artifacts.map(a => a.id);
   321→
   322→  const artifacts = context.graph.getAllArtifacts();
   323→  const ready = new Set(context.graph.getNextArtifacts(context.completed));
   324→  const blocked = context.graph.getBlocked(context.completed);
   325→
   326→  const artifactStatuses: ArtifactStatus[] = artifacts.map(artifact => {
   327→    if (context.completed.has(artifact.id)) {
   328→      return {
   329→        id: artifact.id,
   330→        outputPath: artifact.generates,
   331→        status: 'done' as const,
   332→      };
   333→    }
   334→
   335→    if (ready.has(artifact.id)) {
   336→      return {
   337→        id: artifact.id,
   338→        outputPath: artifact.generates,
   339→        status: 'ready' as const,
   340→      };
   341→    }
   342→
   343→    return {
   344→      id: artifact.id,
   345→      outputPath: artifact.generates,
   346→      status: 'blocked' as const,
   347→      missingDeps: blocked[artifact.id] ?? [],
   348→    };
   349→  });
   350→
   351→  // Sort by build order for consistent output
   352→  const buildOrder = context.graph.getBuildOrder();
   353→  const orderMap = new Map(buildOrder.map((id, idx) => [id, idx]));
   354→  artifactStatuses.sort((a, b) => (orderMap.get(a.id) ?? 0) - (orderMap.get(b.id) ?? 0));
   355→
   356→  return {
   357→    changeName: context.changeName,
   358→    schemaName: context.schemaName,
   359→    isComplete: context.graph.isComplete(context.completed),
   360→    applyRequires,
   361→    artifacts: artifactStatuses,
   362→  };
   363→}
