    24→
    25→export async function newChangeCommand(name: string | undefined, options: NewChangeOptions): Promise<void> {
    26→  if (!name) {
    27→    throw new Error('Missing required argument <name>');
    28→  }
    29→
    30→  const validation = validateChangeName(name);
    31→  if (!validation.valid) {
    32→    throw new Error(validation.error);
    33→  }
    34→
    35→  const projectRoot = process.cwd();
    36→
    37→  // Validate schema if provided
    38→  if (options.schema) {
    39→    validateSchemaExists(options.schema, projectRoot);
    40→  }
    41→
    42→  const schemaDisplay = options.schema ? ` with schema '${options.schema}'` : '';
    43→  const spinner = ora(`Creating change '${name}'${schemaDisplay}...`).start();
    44→
    45→  try {
    46→    const result = await createChange(projectRoot, name, { schema: options.schema });
    47→
    48→    // If description provided, create README.md with description
    49→    if (options.description) {
    50→      const { promises: fs } = await import('fs');
    51→      const changeDir = path.join(projectRoot, 'openspec', 'changes', name);
    52→      const readmePath = path.join(changeDir, 'README.md');
    53→      await fs.writeFile(readmePath, `# ${name}\n\n${options.description}\n`, 'utf-8');
    54→    }
    55→
    56→    spinner.succeed(`Created change '${name}' at openspec/changes/${name}/ (schema: ${result.schema})`);
    57→  } catch (error) {
    58→    spinner.fail(`Failed to create change '${name}'`);
    59→    throw error;
    60→  }
    61→}
