     2→ * Instructions Command
     3→ *
     4→ * Generates enriched instructions for creating artifacts or applying tasks.
     5→ * Includes both artifact instructions and apply instructions.
     6→ */
     7→
     8→import ora from 'ora';
     9→import path from 'path';
    10→import * as fs from 'fs';
    11→import {
    12→  loadChangeContext,
    13→  generateInstructions,
    14→  resolveSchema,
    15→  type ArtifactInstructions,
    16→} from '../../core/artifact-graph/index.js';
    17→import {
    18→  validateChangeExists,
    19→  validateSchemaExists,
    20→  type TaskItem,
    21→  type ApplyInstructions,
    22→} from './shared.js';
    23→
    24→// -----------------------------------------------------------------------------
    25→// Types
    26→// -----------------------------------------------------------------------------
    27→
    28→export interface InstructionsOptions {
    29→  change?: string;
    30→  schema?: string;
    31→  json?: boolean;
    32→}
    33→
    34→export interface ApplyInstructionsOptions {
    35→  change?: string;
    36→  schema?: string;
    37→  json?: boolean;
    38→}
    39→
    40→// -----------------------------------------------------------------------------
    41→// Artifact Instructions Command
    42→// -----------------------------------------------------------------------------
    43→
    44→export async function instructionsCommand(
    45→  artifactId: string | undefined,
    46→  options: InstructionsOptions
    47→): Promise<void> {
    48→  const spinner = ora('Generating instructions...').start();
    49→
    50→  try {
    51→    const projectRoot = process.cwd();
    52→    const changeName = await validateChangeExists(options.change, projectRoot);
    53→
    54→    // Validate schema if explicitly provided
    55→    if (options.schema) {
    56→      validateSchemaExists(options.schema, projectRoot);
    57→    }
    58→
    59→    // loadChangeContext will auto-detect schema from metadata if not provided
    60→    const context = loadChangeContext(projectRoot, changeName, options.schema);
    61→
    62→    if (!artifactId) {
    63→      spinner.stop();
    64→      const validIds = context.graph.getAllArtifacts().map((a) => a.id);
    65→      throw new Error(
    66→        `Missing required argument <artifact>. Valid artifacts:\n  ${validIds.join('\n  ')}`
    67→      );
    68→    }
    69→
    70→    const artifact = context.graph.getArtifact(artifactId);
    71→
    72→    if (!artifact) {
    73→      spinner.stop();
    74→      const validIds = context.graph.getAllArtifacts().map((a) => a.id);
    75→      throw new Error(
    76→        `Artifact '${artifactId}' not found in schema '${context.schemaName}'. Valid artifacts:\n  ${validIds.join('\n  ')}`
    77→      );
    78→    }
    79→
    80→    const instructions = generateInstructions(context, artifactId, projectRoot);
    81→    const isBlocked = instructions.dependencies.some((d) => !d.done);
    82→
    83→    spinner.stop();
    84→
    85→    if (options.json) {
    86→      console.log(JSON.stringify(instructions, null, 2));
    87→      return;
    88→    }
    89→
    90→    printInstructionsText(instructions, isBlocked);
    91→  } catch (error) {
    92→    spinner.stop();
    93→    throw error;
    94→  }
    95→}
    96→
    97→export function printInstructionsText(instructions: ArtifactInstructions, isBlocked: boolean): void {
    98→  const {
    99→    artifactId,
   100→    changeName,
   101→    schemaName,
   102→    changeDir,
   103→    outputPath,
   104→    description,
   105→    instruction,
   106→    context,
   107→    rules,
   108→    template,
   109→    dependencies,
   110→    unlocks,
   111→  } = instructions;
   112→
   113→  // Opening tag
   114→  console.log(`<artifact id="${artifactId}" change="${changeName}" schema="${schemaName}">`);
   115→  console.log();
   116→
   117→  // Warning for blocked artifacts
   118→  if (isBlocked) {
   119→    const missing = dependencies.filter((d) => !d.done).map((d) => d.id);
   120→    console.log('<warning>');
   121→    console.log('This artifact has unmet dependencies. Complete them first or proceed with caution.');
   122→    console.log(`Missing: ${missing.join(', ')}`);
   123→    console.log('</warning>');
   124→    console.log();
   125→  }
   126→
   127→  // Task directive
   128→  console.log('<task>');
   129→  console.log(`Create the ${artifactId} artifact for change "${changeName}".`);
   130→  console.log(description);
   131→  console.log('</task>');
   132→  console.log();
   133→
   134→  // Project context (AI constraint - do not include in output)
   135→  if (context) {
   136→    console.log('<project_context>');
   137→    console.log('<!-- This is background information for you. Do NOT include this in your output. -->');
   138→    console.log(context);
   139→    console.log('</project_context>');
   140→    console.log();
   141→  }
   142→
   143→  // Rules (AI constraint - do not include in output)
   144→  if (rules && rules.length > 0) {
   145→    console.log('<rules>');
   146→    console.log('<!-- These are constraints for you to follow. Do NOT include this in your output. -->');
   147→    for (const rule of rules) {
   148→      console.log(`- ${rule}`);
   149→    }
   150→    console.log('</rules>');
   151→    console.log();
   152→  }
   153→
   154→  // Dependencies (files to read for context)
   155→  if (dependencies.length > 0) {
   156→    console.log('<dependencies>');
   157→    console.log('Read these files for context before creating this artifact:');
   158→    console.log();
   159→    for (const dep of dependencies) {
   160→      const status = dep.done ? 'done' : 'missing';
   161→      const fullPath = path.join(changeDir, dep.path);
   162→      console.log(`<dependency id="${dep.id}" status="${status}">`);
   163→      console.log(`  <path>${fullPath}</path>`);
   164→      console.log(`  <description>${dep.description}</description>`);
   165→      console.log('</dependency>');
   166→    }
   167→    console.log('</dependencies>');
   168→    console.log();
   169→  }
   170→
   171→  // Output location
   172→  console.log('<output>');
   173→  console.log(`Write to: ${path.join(changeDir, outputPath)}`);
   174→  console.log('</output>');
   175→  console.log();
   176→
   177→  // Instruction (guidance)
   178→  if (instruction) {
   179→    console.log('<instruction>');
   180→    console.log(instruction.trim());
   181→    console.log('</instruction>');
   182→    console.log();
   183→  }
   184→
   185→  // Template
   186→  console.log('<template>');
   187→  console.log('<!-- Use this as the structure for your output file. Fill in the sections. -->');
   188→  console.log(template.trim());
   189→  console.log('</template>');
   190→  console.log();
   191→
   192→  // Success criteria placeholder
   193→  console.log('<success_criteria>');
   194→  console.log('<!-- To be defined in schema validation rules -->');
