   210→// -----------------------------------------------------------------------------
   211→// Apply Instructions Command
   212→// -----------------------------------------------------------------------------
   213→
   214→/**
   215→ * Parses tasks.md content and extracts task items with their completion status.
   216→ */
   217→function parseTasksFile(content: string): TaskItem[] {
   218→  const tasks: TaskItem[] = [];
   219→  const lines = content.split('\n');
   220→  let taskIndex = 0;
   221→
   222→  for (const line of lines) {
   223→    // Match checkbox patterns: - [ ] or - [x] or - [X]
   224→    const checkboxMatch = line.match(/^[-*]\s*\[([ xX])\]\s*(.+)\s*$/);
   225→    if (checkboxMatch) {
   226→      taskIndex++;
   227→      const done = checkboxMatch[1].toLowerCase() === 'x';
   228→      const description = checkboxMatch[2].trim();
   229→      tasks.push({
   230→        id: `${taskIndex}`,
   231→        description,
   232→        done,
   233→      });
   234→    }
   235→  }
   236→
   237→  return tasks;
   238→}
   239→
   240→/**
   241→ * Checks if an artifact output exists in the change directory.
   242→ * Supports glob patterns (e.g., "specs/*.md") by verifying at least one matching file exists.
   243→ */
   244→function artifactOutputExists(changeDir: string, generates: string): boolean {
   245→  // Normalize the generates path to use platform-specific separators
   246→  const normalizedGenerates = generates.split('/').join(path.sep);
   247→  const fullPath = path.join(changeDir, normalizedGenerates);
   248→
   249→  // If it's a glob pattern (contains ** or *), check for matching files
   250→  if (generates.includes('*')) {
   251→    // Extract the directory part before the glob pattern
   252→    const parts = normalizedGenerates.split(path.sep);
   253→    const dirParts: string[] = [];
   254→    let patternPart = '';
   255→    for (const part of parts) {
   256→      if (part.includes('*')) {
   257→        patternPart = part;
   258→        break;
   259→      }
   260→      dirParts.push(part);
   261→    }
   262→    const dirPath = path.join(changeDir, ...dirParts);
   263→
   264→    // Check if directory exists
   265→    if (!fs.existsSync(dirPath) || !fs.statSync(dirPath).isDirectory()) {
   266→      return false;
   267→    }
   268→
   269→    // Extract expected extension from pattern (e.g., "*.md" -> ".md")
   270→    const extMatch = patternPart.match(/\*(\.[a-zA-Z0-9]+)$/);
   271→    const expectedExt = extMatch ? extMatch[1] : null;
   272→
   273→    // Recursively check for matching files
   274→    const hasMatchingFiles = (dir: string): boolean => {
   275→      try {
   276→        const entries = fs.readdirSync(dir, { withFileTypes: true });
   277→        for (const entry of entries) {
   278→          if (entry.isDirectory()) {
   279→            // For ** patterns, recurse into subdirectories
   280→            if (generates.includes('**') && hasMatchingFiles(path.join(dir, entry.name))) {
   281→              return true;
   282→            }
   283→          } else if (entry.isFile()) {
   284→            // Check if file matches expected extension (or any file if no extension specified)
   285→            if (!expectedExt || entry.name.endsWith(expectedExt)) {
   286→              return true;
   287→            }
   288→          }
   289→        }
   290→      } catch {
   291→        return false;
   292→      }
   293→      return false;
   294→    };
   295→
   296→    return hasMatchingFiles(dirPath);
   297→  }
   298→
   299→  return fs.existsSync(fullPath);
   300→}
   301→
   302→/**
   303→ * Generates apply instructions for implementing tasks from a change.
   304→ * Schema-aware: reads apply phase configuration from schema to determine
   305→ * required artifacts, tracking file, and instruction.
   306→ */
   307→export async function generateApplyInstructions(
   308→  projectRoot: string,
   309→  changeName: string,
   310→  schemaName?: string
   311→): Promise<ApplyInstructions> {
   312→  // loadChangeContext will auto-detect schema from metadata if not provided
   313→  const context = loadChangeContext(projectRoot, changeName, schemaName);
   314→  const changeDir = path.join(projectRoot, 'openspec', 'changes', changeName);
   315→
   316→  // Get the full schema to access the apply phase configuration
   317→  const schema = resolveSchema(context.schemaName, projectRoot);
   318→  const applyConfig = schema.apply;
   319→
   320→  // Determine required artifacts and tracking file from schema
   321→  // Fallback: if no apply block, require all artifacts
   322→  const requiredArtifactIds = applyConfig?.requires ?? schema.artifacts.map((a) => a.id);
   323→  const tracksFile = applyConfig?.tracks ?? null;
   324→  const schemaInstruction = applyConfig?.instruction ?? null;
   325→
   326→  // Check which required artifacts are missing
   327→  const missingArtifacts: string[] = [];
   328→  for (const artifactId of requiredArtifactIds) {
   329→    const artifact = schema.artifacts.find((a) => a.id === artifactId);
   330→    if (artifact && !artifactOutputExists(changeDir, artifact.generates)) {
   331→      missingArtifacts.push(artifactId);
   332→    }
   333→  }
   334→
   335→  // Build context files from all existing artifacts in schema
   336→  const contextFiles: Record<string, string> = {};
   337→  for (const artifact of schema.artifacts) {
   338→    if (artifactOutputExists(changeDir, artifact.generates)) {
   339→      contextFiles[artifact.id] = path.join(changeDir, artifact.generates);
   340→    }
   341→  }
   342→
   343→  // Parse tasks if tracking file exists
   344→  let tasks: TaskItem[] = [];
   345→  let tracksFileExists = false;
   346→  if (tracksFile) {
   347→    const tracksPath = path.join(changeDir, tracksFile);
   348→    tracksFileExists = fs.existsSync(tracksPath);
   349→    if (tracksFileExists) {
   350→      const tasksContent = await fs.promises.readFile(tracksPath, 'utf-8');
   351→      tasks = parseTasksFile(tasksContent);
   352→    }
   353→  }
   354→
   355→  // Calculate progress
   356→  const total = tasks.length;
   357→  const complete = tasks.filter((t) => t.done).length;
   358→  const remaining = total - complete;
   359→
   360→  // Determine state and instruction
   361→  let state: ApplyInstructions['state'];
   362→  let instruction: string;
   363→
   364→  if (missingArtifacts.length > 0) {
   365→    state = 'blocked';
   366→    instruction = `Cannot apply this change yet. Missing artifacts: ${missingArtifacts.join(', ')}.\nUse the openspec-continue-change skill to create the missing artifacts first.`;
   367→  } else if (tracksFile && !tracksFileExists) {
   368→    // Tracking file configured but doesn't exist yet
   369→    const tracksFilename = path.basename(tracksFile);
   370→    state = 'blocked';
   371→    instruction = `The ${tracksFilename} file is missing and must be created.\nUse openspec-continue-change to generate the tracking file.`;
   372→  } else if (tracksFile && tracksFileExists && total === 0) {
   373→    // Tracking file exists but contains no tasks
   374→    const tracksFilename = path.basename(tracksFile);
   375→    state = 'blocked';
   376→    instruction = `The ${tracksFilename} file exists but contains no tasks.\nAdd tasks to ${tracksFilename} or regenerate it with openspec-continue-change.`;
   377→  } else if (tracksFile && remaining === 0 && total > 0) {
   378→    state = 'all_done';
   379→    instruction = 'All tasks are complete! This change is ready to be archived.\nConsider running tests and reviewing the changes before archiving.';
   380→  } else if (!tracksFile) {
   381→    // No tracking file configured in schema - ready to apply
   382→    state = 'ready';
   383→    instruction = schemaInstruction?.trim() ?? 'All required artifacts complete. Proceed with implementation.';
   384→  } else {
   385→    state = 'ready';
   386→    instruction = schemaInstruction?.trim() ?? 'Read context files, work through pending tasks, mark complete as you go.\nPause if you hit blockers or need clarification.';
   387→  }
   388→
   389→  return {
   390→    changeName,
   391→    changeDir,
   392→    schemaName: context.schemaName,
   393→    contextFiles,
   394→    progress: { total, complete, remaining },
   395→    tasks,
   396→    state,
   397→    missingArtifacts: missingArtifacts.length > 0 ? missingArtifacts : undefined,
   398→    instruction,
   399→  };
   400→}
   401→
   402→export async function applyInstructionsCommand(options: ApplyInstructionsOptions): Promise<void> {
   403→  const spinner = ora('Generating apply instructions...').start();
   404→
   405→  try {
   406→    const projectRoot = process.cwd();
   407→    const changeName = await validateChangeExists(options.change, projectRoot);
   408→
   409→    // Validate schema if explicitly provided
   410→    if (options.schema) {
   411→      validateSchemaExists(options.schema, projectRoot);
   412→    }
   413→
   414→    // generateApplyInstructions uses loadChangeContext which auto-detects schema
   415→    const instructions = await generateApplyInstructions(projectRoot, changeName, options.schema);
   416→
   417→    spinner.stop();
   418→
   419→    if (options.json) {
   420→      console.log(JSON.stringify(instructions, null, 2));
   421→      return;
   422→    }
   423→
   424→    printApplyInstructionsText(instructions);
   425→  } catch (error) {
   426→    spinner.stop();
   427→    throw error;
   428→  }
   429→}
   430→
   431→export function printApplyInstructionsText(instructions: ApplyInstructions): void {
   432→  const { changeName, schemaName, contextFiles, progress, tasks, state, missingArtifacts, instruction } = instructions;
   433→
   434→  console.log(`## Apply: ${changeName}`);
   435→  console.log(`Schema: ${schemaName}`);
   436→  console.log();
   437→
   438→  // Warning for blocked state
   439→  if (state === 'blocked' && missingArtifacts) {
   440→    console.log('### ⚠️ Blocked');
   441→    console.log();
   442→    console.log(`Missing artifacts: ${missingArtifacts.join(', ')}`);
   443→    console.log('Use the openspec-continue-change skill to create these first.');
   444→    console.log();
   445→  }
   446→
   447→  // Context files (dynamically from schema)
   448→  const contextFileEntries = Object.entries(contextFiles);
   449→  if (contextFileEntries.length > 0) {
   450→    console.log('### Context Files');
   451→    for (const [artifactId, filePath] of contextFileEntries) {
   452→      console.log(`- ${artifactId}: ${filePath}`);
   453→    }
   454→    console.log();
   455→  }
   456→
   457→  // Progress (only show if we have tracking)
   458→  if (progress.total > 0 || tasks.length > 0) {
   459→    console.log('### Progress');
   460→    if (state === 'all_done') {
   461→      console.log(`${progress.complete}/${progress.total} complete ✓`);
   462→    } else {
   463→      console.log(`${progress.complete}/${progress.total} complete`);
   464→    }
   465→    console.log();
   466→  }
   467→
   468→  // Tasks
   469→  if (tasks.length > 0) {
   470→    console.log('### Tasks');
   471→    for (const task of tasks) {
   472→      const checkbox = task.done ? '[x]' : '[ ]';
   473→      console.log(`- ${checkbox} ${task.description}`);
   474→    }
   475→    console.log();
   476→  }
   477→
   478→  // Instruction
   479→  console.log('### Instruction');
   480→  console.log(instruction);
   481→}
