     1→/**
     2→ * Templates Command
     3→ *
     4→ * Shows resolved template paths for all artifacts in a schema.
     5→ */
     6→
     7→import ora from 'ora';
     8→import path from 'path';
     9→import {
    10→  resolveSchema,
    11→  getSchemaDir,
    12→  ArtifactGraph,
    13→} from '../../core/artifact-graph/index.js';
    14→import { validateSchemaExists, DEFAULT_SCHEMA } from './shared.js';
    15→
    16→// -----------------------------------------------------------------------------
    17→// Types
    18→// -----------------------------------------------------------------------------
    19→
    20→export interface TemplatesOptions {
    21→  schema?: string;
    22→  json?: boolean;
    23→}
    24→
    25→export interface TemplateInfo {
    26→  artifactId: string;
    27→  templatePath: string;
    28→  source: 'project' | 'user' | 'package';
    29→}
    30→
    31→// -----------------------------------------------------------------------------
    32→// Command Implementation
    33→// -----------------------------------------------------------------------------
    34→
    35→export async function templatesCommand(options: TemplatesOptions): Promise<void> {
    36→  const spinner = ora('Loading templates...').start();
    37→
    38→  try {
    39→    const projectRoot = process.cwd();
    40→    const schemaName = validateSchemaExists(options.schema ?? DEFAULT_SCHEMA, projectRoot);
    41→    const schema = resolveSchema(schemaName, projectRoot);
    42→    const graph = ArtifactGraph.fromSchema(schema);
    43→    const schemaDir = getSchemaDir(schemaName, projectRoot)!;
    44→
    45→    // Determine the source (project, user, or package)
    46→    const {
    47→      getUserSchemasDir,
    48→      getProjectSchemasDir,
    49→    } = await import('../../core/artifact-graph/resolver.js');
    50→    const projectSchemasDir = getProjectSchemasDir(projectRoot);
    51→    const userSchemasDir = getUserSchemasDir();
    52→
    53→    // Determine source by checking if schemaDir is inside each base directory
    54→    // Using path.relative is more robust than startsWith for path comparisons
    55→    const isInsideDir = (child: string, parent: string): boolean => {
    56→      const relative = path.relative(parent, child);
    57→      return !relative.startsWith('..') && !path.isAbsolute(relative);
    58→    };
    59→
    60→    let source: 'project' | 'user' | 'package';
    61→    if (isInsideDir(schemaDir, projectSchemasDir)) {
    62→      source = 'project';
    63→    } else if (isInsideDir(schemaDir, userSchemasDir)) {
    64→      source = 'user';
    65→    } else {
    66→      source = 'package';
    67→    }
    68→
    69→    const templates: TemplateInfo[] = graph.getAllArtifacts().map((artifact) => ({
    70→      artifactId: artifact.id,
    71→      templatePath: path.join(schemaDir, 'templates', artifact.template),
    72→      source,
    73→    }));
    74→
    75→    spinner.stop();
    76→
    77→    if (options.json) {
    78→      const output: Record<string, { path: string; source: string }> = {};
    79→      for (const t of templates) {
    80→        output[t.artifactId] = { path: t.templatePath, source: t.source };
    81→      }
    82→      console.log(JSON.stringify(output, null, 2));
    83→      return;
    84→    }
    85→
    86→    console.log(`Schema: ${schemaName}`);
    87→    console.log(`Source: ${source}`);
    88→    console.log();
    89→
    90→    for (const t of templates) {
    91→      console.log(`${t.artifactId}:`);
    92→      console.log(`  ${t.templatePath}`);
    93→    }
    94→  } catch (error) {
    95→    spinner.stop();
    96→    throw error;
    97→  }
    98→}
