   123→  // ═══════════════════════════════════════════════════════════
   124→  // VALIDATION & SETUP
   125→  // ═══════════════════════════════════════════════════════════
   126→
   127→  private async validate(
   128→    projectPath: string,
   129→    openspecPath: string
   130→  ): Promise<boolean> {
