   145→
   146→  // ═══════════════════════════════════════════════════════════
   147→  // LEGACY CLEANUP
   148→  // ═══════════════════════════════════════════════════════════
   149→
   150→  private async handleLegacyCleanup(projectPath: string, extendMode: boolean): Promise<void> {
   151→    // Detect legacy artifacts
   152→    const detection = await detectLegacyArtifacts(projectPath);
   153→
   154→    if (!detection.hasLegacyArtifacts) {
   155→      return; // No legacy artifacts found
