   167→      await this.performLegacyCleanup(projectPath, detection);
   168→      return;
   169→    }
   170→
   171→    if (!canPrompt) {
   172→      // Non-interactive mode without --force: abort
   173→      console.log(chalk.red('Legacy files detected in non-interactive mode.'));
   174→      console.log(chalk.dim('Run interactively to upgrade, or use --force to auto-cleanup.'));
   175→      process.exit(1);
   176→    }
   177→
   178→    // Interactive mode: prompt for confirmation
   179→    const { confirm } = await import('@inquirer/prompts');
   180→    const shouldCleanup = await confirm({
