   193→
   194→  private async performLegacyCleanup(projectPath: string, detection: LegacyDetectionResult): Promise<void> {
   195→    const spinner = ora('Cleaning up legacy files...').start();
   196→
   197→    const result = await cleanupLegacyArtifacts(projectPath, detection);
   198→
