   210→  // ═══════════════════════════════════════════════════════════
   211→  // TOOL SELECTION
   212→  // ═══════════════════════════════════════════════════════════
   213→
   214→  private async getSelectedTools(
   215→    toolStates: Map<string, ToolSkillStatus>,
   216→    extendMode: boolean
   217→  ): Promise<string[]> {
   218→    // Check for --tools flag first
   219→    const nonInteractiveSelection = this.resolveToolsArg();
   220→    if (nonInteractiveSelection !== null) {
   221→      return nonInteractiveSelection;
   222→    }
   223→
   224→    const validTools = getToolsWithSkillsDir();
   225→    const canPrompt = this.canPromptInteractively();
   226→
   227→    if (!canPrompt || validTools.length === 0) {
   228→      throw new Error(
   229→        `Missing required option --tools. Valid tools:\n  ${validTools.join('\n  ')}\n\nUse --tools all, --tools none, or --tools claude,cursor,...`
   230→      );
   231→    }
   232→
   233→    // Interactive mode: show searchable multi-select
   234→    const { searchableMultiSelect } = await import('../prompts/searchable-multi-select.js');
   235→
   236→    // Build choices with configured status and sort configured tools first
   237→    const sortedChoices = validTools
   238→      .map((toolId) => {
   239→        const tool = AI_TOOLS.find((t) => t.value === toolId);
   240→        const status = toolStates.get(toolId);
   241→        const configured = status?.configured ?? false;
   242→
   243→        return {
   244→          name: tool?.name || toolId,
   245→          value: toolId,
   246→          configured,
   247→          preSelected: configured, // Pre-select configured tools for easy refresh
   248→        };
   249→      })
   250→      .sort((a, b) => {
   251→        // Configured tools first
   252→        if (a.configured && !b.configured) return -1;
   253→        if (!a.configured && b.configured) return 1;
   254→        return 0;
   255→      });
   256→
   257→    const selectedTools = await searchableMultiSelect({
   258→      message: `Select tools to set up (${validTools.length} available)`,
   259→      pageSize: 15,
   260→      choices: sortedChoices,
   261→      validate: (selected: string[]) => selected.length > 0 || 'Select at least one tool',
   262→    });
   263→
   264→    if (selectedTools.length === 0) {
   265→      throw new Error('At least one tool must be selected');
   266→    }
   267→
   268→    return selectedTools;
   269→  }
