   271→  private resolveToolsArg(): string[] | null {
   272→    if (typeof this.toolsArg === 'undefined') {
   273→      return null;
   274→    }
   275→
   276→    const raw = this.toolsArg.trim();
   277→    if (raw.length === 0) {
   278→      throw new Error(
   279→        'The --tools option requires a value. Use "all", "none", or a comma-separated list of tool IDs.'
   280→      );
   281→    }
   282→
   283→    const availableTools = getToolsWithSkillsDir();
   284→    const availableSet = new Set(availableTools);
   285→    const availableList = ['all', 'none', ...availableTools].join(', ');
   286→
   287→    const lowerRaw = raw.toLowerCase();
   288→    if (lowerRaw === 'all') {
   289→      return availableTools;
   290→    }
   291→
   292→    if (lowerRaw === 'none') {
   293→      return [];
   294→    }
   295→
   296→    const tokens = raw
   297→      .split(',')
   298→      .map((token) => token.trim())
   299→      .filter((token) => token.length > 0);
   300→
   301→    if (tokens.length === 0) {
   302→      throw new Error(
   303→        'The --tools option requires at least one tool ID when not using "all" or "none".'
   304→      );
   305→    }
   306→
   307→    const normalizedTokens = tokens.map((token) => token.toLowerCase());
   308→
   309→    if (normalizedTokens.some((token) => token === 'all' || token === 'none')) {
   310→      throw new Error('Cannot combine reserved values "all" or "none" with specific tool IDs.');
   311→    }
   312→
   313→    const invalidTokens = tokens.filter(
   314→      (_token, index) => !availableSet.has(normalizedTokens[index])
   315→    );
   316→
   317→    if (invalidTokens.length > 0) {
   318→      throw new Error(
   319→        `Invalid tool(s): ${invalidTokens.join(', ')}. Available values: ${availableList}`
   320→      );
   321→    }
   322→
   323→    // Deduplicate while preserving order
   324→    const deduped: string[] = [];
   325→    for (const token of normalizedTokens) {
   326→      if (!deduped.includes(token)) {
   327→        deduped.push(token);
   328→      }
   329→    }
   330→
   331→    return deduped;
   332→  }
