   334→  private validateTools(
   335→    toolIds: string[],
   336→    toolStates: Map<string, ToolSkillStatus>
   337→  ): Array<{ value: string; name: string; skillsDir: string; wasConfigured: boolean }> {
   338→    const validatedTools: Array<{ value: string; name: string; skillsDir: string; wasConfigured: boolean }> = [];
   339→
   340→    for (const toolId of toolIds) {
   341→      const tool = AI_TOOLS.find((t) => t.value === toolId);
   342→      if (!tool) {
   343→        const validToolIds = getToolsWithSkillsDir();
   344→        throw new Error(
   345→          `Unknown tool '${toolId}'. Valid tools:\n  ${validToolIds.join('\n  ')}`
   346→        );
   347→      }
   348→
   349→      if (!tool.skillsDir) {
   350→        const validToolsWithSkills = getToolsWithSkillsDir();
   351→        throw new Error(
   352→          `Tool '${toolId}' does not support skill generation.\nTools with skill generation support:\n  ${validToolsWithSkills.join('\n  ')}`
   353→        );
   354→      }
   355→
   356→      const preState = toolStates.get(tool.value);
   357→      validatedTools.push({
   358→        value: tool.value,
   359→        name: tool.name,
   360→        skillsDir: tool.skillsDir,
   361→        wasConfigured: preState?.configured ?? false,
