   411→  private async generateSkillsAndCommands(
   412→    projectPath: string,
   413→    tools: Array<{ value: string; name: string; skillsDir: string; wasConfigured: boolean }>
   414→  ): Promise<{
   415→    createdTools: typeof tools;
   416→    refreshedTools: typeof tools;
   417→    failedTools: Array<{ name: string; error: Error }>;
   418→    commandsSkipped: string[];
   419→  }> {
   420→    const createdTools: typeof tools = [];
   421→    const refreshedTools: typeof tools = [];
   422→    const failedTools: Array<{ name: string; error: Error }> = [];
   423→    const commandsSkipped: string[] = [];
   424→
   425→    // Get skill and command templates once (shared across all tools)
   426→    const skillTemplates = getSkillTemplates();
   427→    const commandContents = getCommandContents();
   428→
   429→    // Process each tool
   430→    for (const tool of tools) {
   431→      const spinner = ora(`Setting up ${tool.name}...`).start();
   432→
   433→      try {
   434→        // Use tool-specific skillsDir
   435→        const skillsDir = path.join(projectPath, tool.skillsDir, 'skills');
   436→
   437→        // Create skill directories and SKILL.md files
   438→        for (const { template, dirName } of skillTemplates) {
   439→          const skillDir = path.join(skillsDir, dirName);
   440→          const skillFile = path.join(skillDir, 'SKILL.md');
   441→
   442→          // Generate SKILL.md content with YAML frontmatter including generatedBy
   443→          const skillContent = generateSkillContent(template, OPENSPEC_VERSION);
   444→
   445→          // Write the skill file
   446→          await FileSystemUtils.writeFile(skillFile, skillContent);
   447→        }
   448→
   449→        // Generate commands using the adapter system
   450→        const adapter = CommandAdapterRegistry.get(tool.value);
   451→        if (adapter) {
   452→          const generatedCommands = generateCommands(commandContents, adapter);
   453→
   454→          for (const cmd of generatedCommands) {
   455→            const commandFile = path.isAbsolute(cmd.path) ? cmd.path : path.join(projectPath, cmd.path);
   456→            await FileSystemUtils.writeFile(commandFile, cmd.fileContent);
   457→          }
   458→        } else {
   459→          commandsSkipped.push(tool.value);
   460→        }
   461→
   462→        spinner.succeed(`Setup complete for ${tool.name}`);
   463→
   464→        if (tool.wasConfigured) {
   465→          refreshedTools.push(tool);
   466→        } else {
   467→          createdTools.push(tool);
   468→        }
   469→      } catch (error) {
   470→        spinner.fail(`Failed for ${tool.name}`);
   471→        failedTools.push({ name: tool.name, error: error as Error });
   472→      }
   473→    }
   474→
   475→    return { createdTools, refreshedTools, failedTools, commandsSkipped };
   476→  }
