   482→  private async createConfig(openspecPath: string, extendMode: boolean): Promise<'created' | 'exists' | 'skipped'> {
   483→    const configPath = path.join(openspecPath, 'config.yaml');
   484→    const configYmlPath = path.join(openspecPath, 'config.yml');
   485→    const configYamlExists = fs.existsSync(configPath);
   486→    const configYmlExists = fs.existsSync(configYmlPath);
