    49→    // Skip the root 'openspec' command
    50→    if (name && name !== 'openspec') {
    51→      names.unshift(name);
    52→    }
    53→    current = current.parent;
    54→  }
    55→
    56→  return names.join(':') || 'openspec';
    57→}
