     1→import path from 'path';
     2→import { FileSystemUtils } from './file-system.js';
     3→import { writeChangeMetadata, validateSchemaName } from './change-metadata.js';
     4→import { readProjectConfig } from '../core/project-config.js';
     5→
     6→const DEFAULT_SCHEMA = 'spec-driven';
     7→
     8→/**
     9→ * Options for creating a change.
    10→ */
    11→export interface CreateChangeOptions {
    12→  /** The workflow schema to use (default: 'spec-driven') */
    13→  schema?: string;
    14→}
    15→
    16→/**
    17→ * Result of creating a change.
    18→ */
    19→export interface CreateChangeResult {
    20→  /** The schema that was actually used (resolved from options, config, or default) */
    21→  schema: string;
    22→}
    23→
    24→/**
    25→ * Result of validating a change name.
    26→ */
    27→export interface ValidationResult {
    28→  valid: boolean;
    29→  error?: string;
    30→}
    31→
    32→/**
    33→ * Validates that a change name follows kebab-case conventions.
    34→ *
    35→ * Valid names:
    36→ * - Start with a lowercase letter
    37→ * - Contain only lowercase letters, numbers, and hyphens
    38→ * - Do not start or end with a hyphen
    39→ * - Do not contain consecutive hyphens
    40→ *
    41→ * @param name - The change name to validate
    42→ * @returns Validation result with `valid: true` or `valid: false` with an error message
    43→ *
    44→ * @example
    45→ * validateChangeName('add-auth') // { valid: true }
    46→ * validateChangeName('Add-Auth') // { valid: false, error: '...' }
    47→ */
    48→export function validateChangeName(name: string): ValidationResult {
    49→  // Pattern: starts with lowercase letter, followed by lowercase letters/numbers,
    50→  // optionally followed by hyphen + lowercase letters/numbers (repeatable)
    51→  const kebabCasePattern = /^[a-z][a-z0-9]*(-[a-z0-9]+)*$/;
    52→
    53→  if (!name) {
    54→    return { valid: false, error: 'Change name cannot be empty' };
    55→  }
    56→
    57→  if (!kebabCasePattern.test(name)) {
    58→    // Provide specific error messages for common mistakes
    59→    if (/[A-Z]/.test(name)) {
    60→      return { valid: false, error: 'Change name must be lowercase (use kebab-case)' };
    61→    }
    62→    if (/\s/.test(name)) {
    63→      return { valid: false, error: 'Change name cannot contain spaces (use hyphens instead)' };
    64→    }
    65→    if (/_/.test(name)) {
    66→      return { valid: false, error: 'Change name cannot contain underscores (use hyphens instead)' };
    67→    }
    68→    if (name.startsWith('-')) {
    69→      return { valid: false, error: 'Change name cannot start with a hyphen' };
    70→    }
    71→    if (name.endsWith('-')) {
    72→      return { valid: false, error: 'Change name cannot end with a hyphen' };
    73→    }
    74→    if (/--/.test(name)) {
    75→      return { valid: false, error: 'Change name cannot contain consecutive hyphens' };
    76→    }
    77→    if (/[^a-z0-9-]/.test(name)) {
    78→      return { valid: false, error: 'Change name can only contain lowercase letters, numbers, and hyphens' };
    79→    }
    80→    if (/^[0-9]/.test(name)) {
    81→      return { valid: false, error: 'Change name must start with a letter' };
    82→    }
    83→
    84→    return { valid: false, error: 'Change name must follow kebab-case convention (e.g., add-auth, refactor-db)' };
    85→  }
    86→
    87→  return { valid: true };
    88→}
    89→
    90→/**
    91→ * Creates a new change directory with metadata file.
    92→ *
    93→ * @param projectRoot - The root directory of the project (where `openspec/` lives)
    94→ * @param name - The change name (must be valid kebab-case)
    95→ * @param options - Optional settings for the change
    96→ * @throws Error if the change name is invalid
    97→ * @throws Error if the schema name is invalid
    98→ * @throws Error if the change directory already exists
    99→ *
   100→ * @returns Result containing the resolved schema name
   101→ *
   102→ * @example
   103→ * // Creates openspec/changes/add-auth/ with default schema
   104→ * const result = await createChange('/path/to/project', 'add-auth')
   105→ * console.log(result.schema) // 'spec-driven' or value from config
   106→ *
   107→ * @example
   108→ * // Creates openspec/changes/add-auth/ with custom schema
   109→ * const result = await createChange('/path/to/project', 'add-auth', { schema: 'my-workflow' })
   110→ * console.log(result.schema) // 'my-workflow'
   111→ */
   112→export async function createChange(
   113→  projectRoot: string,
   114→  name: string,
   115→  options: CreateChangeOptions = {}
   116→): Promise<CreateChangeResult> {
   117→  // Validate the name first
   118→  const validation = validateChangeName(name);
   119→  if (!validation.valid) {
   120→    throw new Error(validation.error);
   121→  }
   122→
   123→  // Determine schema: explicit option → project config → hardcoded default
   124→  let schemaName: string;
   125→  if (options.schema) {
   126→    schemaName = options.schema;
   127→  } else {
   128→    // Try to read from project config
   129→    try {
   130→      const config = readProjectConfig(projectRoot);
   131→      schemaName = config?.schema ?? DEFAULT_SCHEMA;
   132→    } catch {
   133→      // If config read fails, use default
   134→      schemaName = DEFAULT_SCHEMA;
   135→    }
   136→  }
   137→
   138→  // Validate the resolved schema
   139→  validateSchemaName(schemaName, projectRoot);
   140→
   141→  // Build the change directory path
   142→  const changeDir = path.join(projectRoot, 'openspec', 'changes', name);
   143→
   144→  // Check if change already exists
   145→  if (await FileSystemUtils.directoryExists(changeDir)) {
   146→    throw new Error(`Change '${name}' already exists at ${changeDir}`);
   147→  }
   148→
   149→  // Create the directory (including parent directories if needed)
   150→  await FileSystemUtils.createDirectory(changeDir);
   151→
   152→  // Write metadata file with schema and creation date
   153→  const today = new Date().toISOString().split('T')[0];
   154→  writeChangeMetadata(changeDir, {
   155→    schema: schemaName,
   156→    created: today,
   157→  }, projectRoot);
   158→
   159→  return { schema: schemaName };
   160→}
